import * as C from './style';

function CardProduto() {
    return (
        <C.Card>
            <C.Picture></C.Picture>
            <C.TitleProduto>Classic</C.TitleProduto>
            <C.DescProduto>Burg 180g, +Queijo, +Bacon, Salada e Molho</C.DescProduto>
        </C.Card>
    )
}

export default CardProduto
